<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> tree </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> parser</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">parse</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">source</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> None</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">();</span></span>
